import React, { useState } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';
import { useAuth } from '../context/AuthContext';

const Profile = () => {
  const { user, updateUser } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    name: user?.name || '',
    email: user?.email || '',
    phone: user?.phone || '',
    address: user?.address || '',
    dateOfBirth: user?.dateOfBirth || '',
    licenseNumber: user?.licenseNumber || ''
  });
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Simulate profile update
    updateUser(formData);
    setMessage({ type: 'success', text: 'Profile updated successfully!' });
    setIsEditing(false);
    
    setTimeout(() => {
      setMessage({ type: '', text: '' });
    }, 3000);
  };

  const handleCancel = () => {
    setFormData({
      name: user?.name || '',
      email: user?.email || '',
      phone: user?.phone || '',
      address: user?.address || '',
      dateOfBirth: user?.dateOfBirth || '',
      licenseNumber: user?.licenseNumber || ''
    });
    setIsEditing(false);
  };

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <div style={styles.pageHeader}>
          <h1 style={styles.pageTitle}>My Profile</h1>
          <p style={styles.pageSubtitle}>Manage your personal information</p>
        </div>

        {message.text && (
          <div style={{
            ...styles.message,
            background: message.type === 'success' ? '#d4edda' : '#f8d7da',
            color: message.type === 'success' ? '#155724' : '#721c24'
          }}>
            {message.text}
          </div>
        )}

        <div style={styles.profileContainer}>
          {/* Profile Header */}
          <div style={styles.profileHeader}>
            <div style={styles.profileAvatar}>
              {user?.name?.charAt(0).toUpperCase() || 'U'}
            </div>
            <div style={styles.profileInfo}>
              <h2 style={styles.profileName}>{user?.name || 'User'}</h2>
              <p style={styles.profileEmail}>{user?.email || 'user@example.com'}</p>
              <span style={styles.memberBadge}>Premium Member</span>
            </div>
            <button 
              style={styles.editBtn}
              onClick={() => setIsEditing(!isEditing)}
            >
              {isEditing ? 'Cancel' : 'Edit Profile'}
            </button>
          </div>

          {/* Profile Form */}
          <div style={styles.profileFormContainer}>
            {isEditing ? (
              <form onSubmit={handleSubmit} style={styles.profileForm}>
                <div style={styles.formRow}>
                  <div style={styles.formGroup}>
                    <label style={styles.label} htmlFor="name">Full Name</label>
                    <input
                      type="text"
                      id="name"
                      name="name"
                      value={formData.name}
                      onChange={handleChange}
                      required
                      style={styles.input}
                    />
                  </div>
                  
                  <div style={styles.formGroup}>
                    <label style={styles.label} htmlFor="email">Email Address</label>
                    <input
                      type="email"
                      id="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      required
                      style={styles.input}
                    />
                  </div>
                </div>

                <div style={styles.formRow}>
                  <div style={styles.formGroup}>
                    <label style={styles.label} htmlFor="phone">Phone Number</label>
                    <input
                      type="tel"
                      id="phone"
                      name="phone"
                      value={formData.phone}
                      onChange={handleChange}
                      placeholder="+1 (555) 000-0000"
                      style={styles.input}
                    />
                  </div>
                  
                  <div style={styles.formGroup}>
                    <label style={styles.label} htmlFor="dateOfBirth">Date of Birth</label>
                    <input
                      type="date"
                      id="dateOfBirth"
                      name="dateOfBirth"
                      value={formData.dateOfBirth}
                      onChange={handleChange}
                      style={styles.input}
                    />
                  </div>
                </div>

                <div style={styles.formGroup}>
                  <label style={styles.label} htmlFor="address">Address</label>
                  <input
                    type="text"
                    id="address"
                    name="address"
                    value={formData.address}
                    onChange={handleChange}
                    placeholder="Enter your address"
                    style={styles.input}
                  />
                </div>

                <div style={styles.formGroup}>
                  <label style={styles.label} htmlFor="licenseNumber">Driver's License Number</label>
                  <input
                    type="text"
                    id="licenseNumber"
                    name="licenseNumber"
                    value={formData.licenseNumber}
                    onChange={handleChange}
                    placeholder="Enter your license number"
                    style={styles.input}
                  />
                </div>

                <div style={styles.formActions}>
                  <button type="submit" style={styles.btnPrimary}>
                    Save Changes
                  </button>
                  <button 
                    type="button" 
                    style={styles.btnSecondary}
                    onClick={handleCancel}
                  >
                    Cancel
                  </button>
                </div>
              </form>
            ) : (
              <div style={styles.profileDetails}>
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Full Name</span>
                  <span style={styles.detailValue}>{user?.name || 'Not set'}</span>
                </div>
                
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Email Address</span>
                  <span style={styles.detailValue}>{user?.email || 'Not set'}</span>
                </div>
                
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Phone Number</span>
                  <span style={styles.detailValue}>{formData.phone || 'Not set'}</span>
                </div>
                
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Address</span>
                  <span style={styles.detailValue}>{formData.address || 'Not set'}</span>
                </div>
                
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Date of Birth</span>
                  <span style={styles.detailValue}>{formData.dateOfBirth || 'Not set'}</span>
                </div>
                
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Driver's License</span>
                  <span style={styles.detailValue}>{formData.licenseNumber || 'Not set'}</span>
                </div>
                
                <div style={styles.detailRow}>
                  <span style={styles.detailLabel}>Account Type</span>
                  <span style={styles.detailValue}>Premium Member</span>
                </div>
              </div>
            )}
          </div>

          {/* Change Password Section */}
          <div style={styles.passwordSection}>
            <h3 style={styles.sectionTitle}>Change Password</h3>
            <form style={styles.passwordForm}>
              <div style={styles.formGroup}>
                <label style={styles.label} htmlFor="currentPassword">Current Password</label>
                <input
                  type="password"
                  id="currentPassword"
                  placeholder="Enter current password"
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formGroup}>
                <label style={styles.label} htmlFor="newPassword">New Password</label>
                <input
                  type="password"
                  id="newPassword"
                  placeholder="Enter new password"
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formGroup}>
                <label style={styles.label} htmlFor="confirmPassword">Confirm New Password</label>
                <input
                  type="password"
                  id="confirmPassword"
                  placeholder="Confirm new password"
                  style={styles.input}
                />
              </div>
              
              <button type="submit" style={styles.btnPrimary}>
                Update Password
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #e9eefb, #f9fbfe)',
  },
  dashboardContent: {
    marginLeft: '250px',
    marginTop: '60px',
    padding: '30px',
    overflowY: 'auto',
  },
  pageHeader: {
    marginBottom: '20px',
  },
  pageTitle: {
    color: '#121253',
    fontSize: '28px',
    fontWeight: '700',
    margin: '0 0 5px 0',
  },
  pageSubtitle: {
    color: '#555',
    fontSize: '14px',
    margin: 0,
  },
  message: {
    padding: '15px 20px',
    borderRadius: '8px',
    marginBottom: '20px',
    border: '1px solid',
  },
  profileContainer: {
    background: 'white',
    borderRadius: '8px',
    boxShadow: '0 5px 15px rgb(56 56 92 / 0.1)',
    padding: '30px',
  },
  profileHeader: {
    display: 'flex',
    alignItems: 'center',
    gap: '20px',
    paddingBottom: '30px',
    borderBottom: '1px solid #eee',
    marginBottom: '30px',
    flexWrap: 'wrap',
  },
  profileAvatar: {
    width: '80px',
    height: '80px',
    borderRadius: '50%',
    background: '#3f42c7',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: 'white',
    fontSize: '32px',
    fontWeight: 'bold',
  },
  profileInfo: {
    flex: 1,
  },
  profileName: {
    color: '#121253',
    margin: '0 0 5px 0',
    fontSize: '24px',
  },
  profileEmail: {
    color: '#555',
    margin: '0 0 10px 0',
  },
  memberBadge: {
    background: '#00C91E',
    color: 'white',
    padding: '5px 12px',
    borderRadius: '20px',
    fontSize: '12px',
    fontWeight: '600',
  },
  editBtn: {
    background: '#6b7280',
    border: 'none',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  profileFormContainer: {
    marginBottom: '30px',
  },
  profileForm: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  formRow: {
    display: 'flex',
    gap: '20px',
    flexWrap: 'wrap',
  },
  formGroup: {
    flex: '1',
    minWidth: '200px',
  },
  label: {
    display: 'block',
    marginBottom: '8px',
    color: '#555',
    fontWeight: '500',
    fontSize: '14px',
  },
  input: {
    width: '100%',
    padding: '12px 15px',
    border: '1px solid #ddd',
    borderRadius: '6px',
    fontSize: '14px',
    outline: 'none',
  },
  formActions: {
    display: 'flex',
    gap: '10px',
    marginTop: '10px',
  },
  btnPrimary: {
    background: '#3f42c7',
    border: 'none',
    color: 'white',
    padding: '12px 25px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  btnSecondary: {
    background: '#6b7280',
    border: 'none',
    color: 'white',
    padding: '12px 25px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  profileDetails: {
    display: 'flex',
    flexDirection: 'column',
    gap: '15px',
  },
  detailRow: {
    display: 'flex',
    justifyContent: 'space-between',
    padding: '15px',
    background: '#f8f9fa',
    borderRadius: '6px',
    flexWrap: 'wrap',
  },
  detailLabel: {
    color: '#555',
    fontWeight: '500',
  },
  detailValue: {
    color: '#121253',
    fontWeight: '600',
  },
  passwordSection: {
    borderTop: '1px solid #eee',
    paddingTop: '30px',
  },
  sectionTitle: {
    color: '#121253',
    margin: '0 0 20px 0',
    fontSize: '20px',
  },
  passwordForm: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
    maxWidth: '500px',
  },
};

export default Profile;
